use clap::{Parser, ValueEnum};
use std::io::{self, Read, Write, BufWriter};
use std::process::ExitCode;

#[derive(Copy, Clone, ValueEnum, Debug, PartialEq)]
#[clap(rename_all = "lower")]
enum Style {
    None,
    Ascii,
    Ascii2,
    Sharp,
    Rounded,
    Reinforced,
    Markdown,
    Grid,
}

#[derive(Copy, Clone, ValueEnum, Debug, PartialEq)]
#[clap(rename_all = "lower")]
enum Align {
    Left,
    Center,
    Right,
}

#[derive(Parser, Debug)]
#[clap(name = "csview", version = "1.3.4",
       about = "A high performance csv viewer with cjk/emoji support.")]
struct App {
    /// Specify that the input has no header row
    #[clap(short = 'H', long)]
    no_headers: bool,

    /// Prepend a column of line numbers to the table
    #[clap(short = 'n', long)]
    number: bool,

    /// Use '\t' as delimiter for tsv
    #[clap(short = 't', long, conflicts_with = "delimiter")]
    tsv: bool,

    /// Specify the field delimiter
    #[clap(short = 'd', long, default_value_t = ',')]
    delimiter: char,

    /// Specify the border style
    #[clap(short = 's', long, value_enum, default_value_t = Style::Sharp)]
    style: Style,

    /// Specify padding for table cell
    #[clap(short = 'p', long, default_value_t = 1)]
    padding: usize,

    /// Specify global indent for table
    #[clap(short = 'i', long, default_value_t = 0)]
    indent: usize,

    /// Limit column widths sniffing to the specified number of rows. Specify "0" to cancel limit
    #[clap(long, value_name = "LIMIT", default_value_t = 1000)]
    sniff: usize,

    /// Specify the alignment of the table header
    #[clap(long, value_enum, default_value_t = Align::Center)]
    header_align: Align,

    /// Specify the alignment of the table body
    #[clap(long, value_enum, default_value_t = Align::Left)]
    body_align: Align,

    /// Disable pager
    #[clap(short = 'P', long)]
    disable_pager: bool,

    /// File to view
    file: Option<std::path::PathBuf>,
}

fn main() -> ExitCode {
    let app = App::parse();
    match run(app) {
        Ok(()) => ExitCode::SUCCESS,
        Err(e) => {
            eprintln!("csview: {}", e);
            ExitCode::FAILURE
        }
    }
}

fn run(app: App) -> Result<(), String> {
    let delim = if app.tsv { b'\t' } else {
        let mut buf = [0u8; 4];
        let s = app.delimiter.encode_utf8(&mut buf);
        if s.len() != 1 {
            return Err(format!("delimiter must be 1 ASCII byte"));
        }
        buf[0]
    };

    let mut input: Box<dyn Read> = match &app.file {
        Some(p) => {
            match std::fs::File::open(p) {
                Ok(f) => Box::new(f),
                Err(e) => return Err(format_io_err(&e)),
            }
        }
        None => {
            use std::io::IsTerminal;
            if io::stdin().is_terminal() {
                return Err("no input file specified (use -h for help)".to_string());
            }
            Box::new(io::stdin())
        }
    };

    let mut all = Vec::new();
    if let Err(e) = input.read_to_end(&mut all) {
        return Err(format_io_err(&e));
    }

    process(&app, &all, delim)
}

fn format_io_err(e: &std::io::Error) -> String {
    if let Some(c) = e.raw_os_error() {
        let msg = match c {
            2 => "No such file or directory",
            13 => "Permission denied",
            21 => "Is a directory",
            _ => "I/O error",
        };
        format!("{} (os error {})", msg, c)
    } else {
        e.to_string()
    }
}

fn process(app: &App, data: &[u8], delim: u8) -> Result<(), String> {
    let mut rdr = csv::ReaderBuilder::new()
        .delimiter(delim)
        .has_headers(false)
        .flexible(false)
        .from_reader(data);

    // Read records
    let mut header: Option<Vec<String>> = None;
    let mut all_records: Vec<Vec<String>> = Vec::new();

    let mut rec_iter = rdr.records();
    if !app.no_headers {
        match rec_iter.next() {
            Some(Ok(r)) => {
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                if !v.is_empty() {
                    header = Some(v);
                }
            }
            Some(Err(e)) => return Err(format_csv_err(&e)),
            None => {}
        }
    }

    // Buffer up to sniff body records
    let sniff_limit = if app.sniff == 0 { usize::MAX } else { app.sniff };
    let mut buffered: Vec<Vec<String>> = Vec::new();
    let mut next_unbuffered: Option<Vec<String>> = None;
    let mut errored_after_buffer = false;
    let mut error_msg = String::new();

    loop {
        if buffered.len() >= sniff_limit {
            break;
        }
        match rec_iter.next() {
            Some(Ok(r)) => {
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                buffered.push(v);
            }
            Some(Err(e)) => {
                errored_after_buffer = true;
                error_msg = format_csv_err(&e);
                break;
            }
            None => break,
        }
    }

    // Determine column count
    let num_cols = if let Some(h) = &header {
        h.len()
    } else if !buffered.is_empty() {
        buffered[0].len()
    } else {
        0
    };

    // Add # column if needed
    let cols_with_num = if app.number { num_cols + 1 } else { num_cols };

    // Compute widths
    let mut widths = vec![0usize; cols_with_num];

    if app.number {
        // # col width: from "#" header (if !no_headers) or 0; will be updated by body row numbers
        if !app.no_headers {
            widths[0] = display_width("#");
        }
    }

    let body_offset = if app.number { 1 } else { 0 };
    if let Some(h) = &header {
        for (i, s) in h.iter().enumerate() {
            let w = display_width(s);
            if w > widths[i + body_offset] {
                widths[i + body_offset] = w;
            }
        }
    }
    for (idx, row) in buffered.iter().enumerate() {
        if app.number {
            let num_str = format!("{}", idx + 1);
            let w = display_width(&num_str);
            if w > widths[0] {
                widths[0] = w;
            }
        }
        for (i, s) in row.iter().enumerate() {
            if i + body_offset >= widths.len() { break; }
            let w = display_width(s);
            if w > widths[i + body_offset] {
                widths[i + body_offset] = w;
            }
        }
    }

    // Streaming pre-fetch: we need to know what row numbers come next if more rows arrive.
    // Width is already locked from buffered, so streaming rows just use locked widths.

    // Now print
    let stdout = io::stdout();
    let mut out = BufWriter::new(stdout.lock());
    let style_def = get_style(app.style);
    let indent_str: String = std::iter::repeat(' ').take(app.indent).collect();
    let pad_str: String = std::iter::repeat(' ').take(app.padding).collect();

    // Top border
    if let Some(top) = &style_def.top {
        write_border(&mut out, &indent_str, top, &widths, app.padding)?;
    }

    // Header row
    let has_header_text = if app.no_headers {
        false
    } else if app.number && cols_with_num > 0 {
        // # column with header "#"
        true
    } else {
        header.is_some()
    };

    if has_header_text {
        let mut row_cells: Vec<String> = Vec::with_capacity(cols_with_num);
        if app.number {
            row_cells.push("#".to_string());
        }
        if let Some(h) = &header {
            for s in h {
                row_cells.push(s.clone());
            }
        } else {
            // -H not set but no header was read? Shouldn't happen if header logic is right
        }
        // Fill if missing
        while row_cells.len() < cols_with_num {
            row_cells.push(String::new());
        }
        write_data_row(&mut out, &indent_str, &pad_str, &style_def, &row_cells, &widths, app.header_align)?;
    }

    // Header separator: only if we have header AND body rows
    let total_body_rows_known = buffered.len() + (if errored_after_buffer { 0 } else { 0 });
    // We need to know if there are body rows AT ALL (buffered or streamable).
    // If sniff_limit was reached we may have more rows. If buffered is empty AND no error AND we haven't tried, try peeking.
    let mut peeked: Option<Result<csv::StringRecord, csv::Error>> = None;
    if has_header_text && total_body_rows_known == 0 && !errored_after_buffer {
        // Try to peek one more record
        match rec_iter.next() {
            Some(r) => peeked = Some(r),
            None => {}
        }
    }
    let has_body = total_body_rows_known > 0 || peeked.as_ref().map_or(false, |r| r.is_ok());

    if has_header_text && has_body {
        if let Some(hsep) = &style_def.header_sep {
            write_border(&mut out, &indent_str, hsep, &widths, app.padding)?;
        }
    }

    // Print buffered body rows
    for (idx, row) in buffered.iter().enumerate() {
        if app.number {
            let mut full_row = vec![format!("{}", idx + 1)];
            full_row.extend(row.iter().cloned());
            write_data_row(&mut out, &indent_str, &pad_str, &style_def, &full_row, &widths, app.body_align)?;
        } else {
            write_data_row(&mut out, &indent_str, &pad_str, &style_def, row, &widths, app.body_align)?;
        }
        // grid: body separator between body rows
        // (only between rows, not after last)
    }

    // Print peeked row if any
    let mut row_count = buffered.len();
    if let Some(r) = peeked {
        match r {
            Ok(rec) => {
                if style_def.body_sep.is_some() && row_count > 0 {
                    write_border(&mut out, &indent_str, style_def.body_sep.as_ref().unwrap(), &widths, app.padding)?;
                }
                let row: Vec<String> = rec.iter().map(|s| s.to_string()).collect();
                row_count += 1;
                if app.number {
                    let mut full_row = vec![format!("{}", row_count)];
                    full_row.extend(row.iter().cloned());
                    write_data_row(&mut out, &indent_str, &pad_str, &style_def, &full_row, &widths, app.body_align)?;
                } else {
                    write_data_row(&mut out, &indent_str, &pad_str, &style_def, &row, &widths, app.body_align)?;
                }
            }
            Err(e) => {
                let _ = out.flush();
                return Err(format_csv_err(&e));
            }
        }
    }

    // Body separators within buffered (between rows for grid)
    // Hmm - I printed all buffered rows without separators. Need to re-do this.
    // Will restructure.

    // Stream remaining
    if !errored_after_buffer {
        loop {
            match rec_iter.next() {
                Some(Ok(rec)) => {
                    if style_def.body_sep.is_some() {
                        write_border(&mut out, &indent_str, style_def.body_sep.as_ref().unwrap(), &widths, app.padding)?;
                    }
                    let row: Vec<String> = rec.iter().map(|s| s.to_string()).collect();
                    row_count += 1;
                    if app.number {
                        let mut full_row = vec![format!("{}", row_count)];
                        full_row.extend(row.iter().cloned());
                        write_data_row(&mut out, &indent_str, &pad_str, &style_def, &full_row, &widths, app.body_align)?;
                    } else {
                        write_data_row(&mut out, &indent_str, &pad_str, &style_def, &row, &widths, app.body_align)?;
                    }
                }
                Some(Err(e)) => {
                    let _ = out.flush();
                    return Err(format_csv_err(&e));
                }
                None => break,
            }
        }
    } else {
        let _ = out.flush();
        return Err(error_msg);
    }

    // Bottom border
    if let Some(bot) = &style_def.bottom {
        write_border(&mut out, &indent_str, bot, &widths, app.padding)?;
    }

    let _ = out.flush();
    Ok(())
}

fn format_csv_err(e: &csv::Error) -> String {
    use csv::ErrorKind;
    match e.kind() {
        ErrorKind::Utf8 { pos, err } => {
            if let Some(pos) = pos {
                format!("CSV parse error: record {} (line {}, field: {}, byte: {}): invalid utf-8: {}",
                    pos.record(), pos.line(), err.field(), pos.byte(), err)
            } else {
                format!("CSV parse error: invalid utf-8: {}", err)
            }
        }
        ErrorKind::UnequalLengths { pos, expected_len, len } => {
            if let Some(pos) = pos {
                format!("CSV error: record {} (line: {}, byte: {}): found record with {} fields, but the previous record has {} fields",
                    pos.record(), pos.line(), pos.byte(), len, expected_len)
            } else {
                format!("CSV error: found record with {} fields, but the previous record has {} fields", len, expected_len)
            }
        }
        _ => format!("{}", e),
    }
}

struct StyleDef {
    top: Option<BorderLine>,
    bottom: Option<BorderLine>,
    header_sep: Option<BorderLine>,
    body_sep: Option<BorderLine>,
    side: String,
    cell_sep: String,
    outer_left: String,
    outer_right: String,
    use_cell_sep: bool,
}

struct BorderLine {
    left: String,
    fill: String,
    tee: String,
    right: String,
}

fn get_style(s: Style) -> StyleDef {
    match s {
        Style::None => StyleDef {
            top: None,
            bottom: None,
            header_sep: None,
            body_sep: None,
            side: String::new(),
            cell_sep: String::new(),
            outer_left: String::new(),
            outer_right: String::new(),
            use_cell_sep: false,
        },
        Style::Ascii => StyleDef {
            top: Some(BorderLine { left: "+".into(), fill: "-".into(), tee: "+".into(), right: "+".into() }),
            bottom: Some(BorderLine { left: "+".into(), fill: "-".into(), tee: "+".into(), right: "+".into() }),
            header_sep: Some(BorderLine { left: "+".into(), fill: "-".into(), tee: "+".into(), right: "+".into() }),
            body_sep: None,
            side: "|".into(),
            cell_sep: "|".into(),
            outer_left: "|".into(),
            outer_right: "|".into(),
            use_cell_sep: true,
        },
        Style::Ascii2 => StyleDef {
            top: None,
            bottom: None,
            header_sep: Some(BorderLine { left: " ".into(), fill: "-".into(), tee: "+".into(), right: " ".into() }),
            body_sep: None,
            side: " ".into(),
            cell_sep: "|".into(),
            outer_left: " ".into(),
            outer_right: " ".into(),
            use_cell_sep: true,
        },
        Style::Sharp => StyleDef {
            top: Some(BorderLine { left: "┌".into(), fill: "─".into(), tee: "┬".into(), right: "┐".into() }),
            bottom: Some(BorderLine { left: "└".into(), fill: "─".into(), tee: "┴".into(), right: "┘".into() }),
            header_sep: Some(BorderLine { left: "├".into(), fill: "─".into(), tee: "┼".into(), right: "┤".into() }),
            body_sep: None,
            side: "│".into(),
            cell_sep: "│".into(),
            outer_left: "│".into(),
            outer_right: "│".into(),
            use_cell_sep: true,
        },
        Style::Rounded => StyleDef {
            top: Some(BorderLine { left: "╭".into(), fill: "─".into(), tee: "┬".into(), right: "╮".into() }),
            bottom: Some(BorderLine { left: "╰".into(), fill: "─".into(), tee: "┴".into(), right: "╯".into() }),
            header_sep: Some(BorderLine { left: "├".into(), fill: "─".into(), tee: "┼".into(), right: "┤".into() }),
            body_sep: None,
            side: "│".into(),
            cell_sep: "│".into(),
            outer_left: "│".into(),
            outer_right: "│".into(),
            use_cell_sep: true,
        },
        Style::Reinforced => StyleDef {
            top: Some(BorderLine { left: "┏".into(), fill: "─".into(), tee: "┬".into(), right: "┓".into() }),
            bottom: Some(BorderLine { left: "┗".into(), fill: "─".into(), tee: "┴".into(), right: "┛".into() }),
            header_sep: Some(BorderLine { left: "├".into(), fill: "─".into(), tee: "┼".into(), right: "┤".into() }),
            body_sep: None,
            side: "│".into(),
            cell_sep: "│".into(),
            outer_left: "│".into(),
            outer_right: "│".into(),
            use_cell_sep: true,
        },
        Style::Markdown => StyleDef {
            top: None,
            bottom: None,
            header_sep: Some(BorderLine { left: "|".into(), fill: "-".into(), tee: "|".into(), right: "|".into() }),
            body_sep: None,
            side: "|".into(),
            cell_sep: "|".into(),
            outer_left: "|".into(),
            outer_right: "|".into(),
            use_cell_sep: true,
        },
        Style::Grid => StyleDef {
            top: Some(BorderLine { left: "┌".into(), fill: "─".into(), tee: "┬".into(), right: "┐".into() }),
            bottom: Some(BorderLine { left: "└".into(), fill: "─".into(), tee: "┴".into(), right: "┘".into() }),
            header_sep: Some(BorderLine { left: "├".into(), fill: "─".into(), tee: "┼".into(), right: "┤".into() }),
            body_sep: Some(BorderLine { left: "├".into(), fill: "─".into(), tee: "┼".into(), right: "┤".into() }),
            side: "│".into(),
            cell_sep: "│".into(),
            outer_left: "│".into(),
            outer_right: "│".into(),
            use_cell_sep: true,
        },
    }
}

fn write_border<W: Write>(out: &mut W, indent: &str, line: &BorderLine,
                          widths: &[usize], padding: usize) -> Result<(), String> {
    let mut buf = String::new();
    buf.push_str(indent);
    buf.push_str(&line.left);
    for (i, w) in widths.iter().enumerate() {
        if i > 0 {
            buf.push_str(&line.tee);
        }
        let span = w + 2 * padding;
        for _ in 0..span {
            buf.push_str(&line.fill);
        }
    }
    buf.push_str(&line.right);
    buf.push('\n');
    out.write_all(buf.as_bytes()).map_err(|e| format!("{}", e))?;
    Ok(())
}

fn write_data_row<W: Write>(out: &mut W, indent: &str, pad: &str, style: &StyleDef,
                            cells: &[String], widths: &[usize], align: Align) -> Result<(), String> {
    let mut buf = String::new();
    buf.push_str(indent);
    buf.push_str(&style.outer_left);
    for (i, _w) in widths.iter().enumerate() {
        if i > 0 && style.use_cell_sep {
            buf.push_str(&style.cell_sep);
        }
        let cell = cells.get(i).map(|s| s.as_str()).unwrap_or("");
        let w = widths[i];
        let (trunc, content_w) = truncate_to_width(cell, w);
        buf.push_str(pad);
        let space_total = w - content_w;
        match align {
            Align::Left => {
                buf.push_str(trunc);
                for _ in 0..space_total { buf.push(' '); }
            }
            Align::Right => {
                for _ in 0..space_total { buf.push(' '); }
                buf.push_str(trunc);
            }
            Align::Center => {
                let l = space_total / 2;
                let r = space_total - l;
                for _ in 0..l { buf.push(' '); }
                buf.push_str(trunc);
                for _ in 0..r { buf.push(' '); }
            }
        }
        buf.push_str(pad);
    }
    buf.push_str(&style.outer_right);
    buf.push('\n');
    out.write_all(buf.as_bytes()).map_err(|e| format!("{}", e))?;
    Ok(())
}

fn truncate_to_width(s: &str, max: usize) -> (&str, usize) {
    let mut acc = 0;
    let mut end_byte = 0;
    for (i, c) in s.char_indices() {
        let w = char_width(c);
        if acc + w > max {
            return (&s[..i], acc);
        }
        acc += w;
        end_byte = i + c.len_utf8();
    }
    (&s[..end_byte], acc)
}

fn display_width(s: &str) -> usize {
    s.chars().map(char_width).sum()
}

fn char_width(c: char) -> usize {
    if c.is_control() {
        return 1;
    }
    use unicode_width::UnicodeWidthChar;
    c.width_cjk().unwrap_or(0)
}

use clap::{Parser, ValueEnum};
use std::io::{self, Read, Write, BufWriter};
use std::process::ExitCode;

#[derive(Copy, Clone, ValueEnum, Debug, PartialEq)]
#[clap(rename_all = "lower")]
enum Style {
    None,
    Ascii,
    Ascii2,
    Sharp,
    Rounded,
    Reinforced,
    Markdown,
    Grid,
}

#[derive(Copy, Clone, ValueEnum, Debug, PartialEq)]
#[clap(rename_all = "lower")]
enum Align {
    Left,
    Center,
    Right,
}

#[derive(Parser, Debug)]
#[clap(name = "csview", version = "1.3.4",
       about = "A high performance csv viewer with cjk/emoji support.")]
struct App {
    /// Specify that the input has no header row
    #[clap(short = 'H', long)]
    no_headers: bool,

    /// Prepend a column of line numbers to the table
    #[clap(short = 'n', long)]
    number: bool,

    /// Use '\t' as delimiter for tsv
    #[clap(short = 't', long, conflicts_with = "delimiter")]
    tsv: bool,

    /// Specify the field delimiter
    #[clap(short = 'd', long, default_value_t = ',')]
    delimiter: char,

    /// Specify the border style
    #[clap(short = 's', long, value_enum, default_value_t = Style::Sharp)]
    style: Style,

    /// Specify padding for table cell
    #[clap(short = 'p', long, default_value_t = 1)]
    padding: usize,

    /// Specify global indent for table
    #[clap(short = 'i', long, default_value_t = 0)]
    indent: usize,

    /// Limit column widths sniffing to the specified number of rows. Specify "0" to cancel limit
    #[clap(long, value_name = "LIMIT", default_value_t = 1000)]
    sniff: usize,

    /// Specify the alignment of the table header
    #[clap(long, value_enum, default_value_t = Align::Center)]
    header_align: Align,

    /// Specify the alignment of the table body
    #[clap(long, value_enum, default_value_t = Align::Left)]
    body_align: Align,

    /// Disable pager
    #[clap(short = 'P', long)]
    disable_pager: bool,

    /// File to view
    file: Option<std::path::PathBuf>,
}

fn main() -> ExitCode {
    let app = App::parse();
    match run(app) {
        Ok(()) => ExitCode::SUCCESS,
        Err(e) => {
            eprintln!("csview: {}", e);
            ExitCode::FAILURE
        }
    }
}

fn run(app: App) -> Result<(), String> {
    let delim = if app.tsv { b'\t' } else {
        let mut buf = [0u8; 4];
        let s = app.delimiter.encode_utf8(&mut buf);
        if s.len() != 1 {
            return Err(format!("delimiter must be 1 ASCII byte"));
        }
        buf[0]
    };

    let mut input: Box<dyn Read> = match &app.file {
        Some(p) => {
            match std::fs::File::open(p) {
                Ok(f) => Box::new(f),
                Err(e) => return Err(format_io_err(&e)),
            }
        }
        None => {
            use std::io::IsTerminal;
            if io::stdin().is_terminal() {
                return Err("no input file specified (use -h for help)".to_string());
            }
            Box::new(io::stdin())
        }
    };

    let mut all = Vec::new();
    if let Err(e) = input.read_to_end(&mut all) {
        return Err(format_io_err(&e));
    }

    process(&app, &all, delim)
}

fn format_io_err(e: &std::io::Error) -> String {
    if let Some(c) = e.raw_os_error() {
        let msg = match c {
            2 => "No such file or directory",
            13 => "Permission denied",
            21 => "Is a directory",
            _ => "I/O error",
        };
        format!("{} (os error {})", msg, c)
    } else {
        e.to_string()
    }
}

fn process(app: &App, data: &[u8], delim: u8) -> Result<(), String> {
    let mut rdr = csv::ReaderBuilder::new()
        .delimiter(delim)
        .has_headers(false)
        .flexible(false)
        .from_reader(data);

    // Read records
    let mut header: Option<Vec<String>> = None;
    let mut all_records: Vec<Vec<String>> = Vec::new();

    let mut rec_iter = rdr.records();
    if !app.no_headers {
        match rec_iter.next() {
            Some(Ok(r)) => {
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                if !v.is_empty() {
                    header = Some(v);
                }
            }
            Some(Err(e)) => return Err(format_csv_err(&e)),
            None => {}
        }
    }

    // Buffer up to sniff body records
    let sniff_limit = if app.sniff == 0 { usize::MAX } else { app.sniff };
    let mut buffered: Vec<Vec<String>> = Vec::new();
    let mut next_unbuffered: Option<Vec<String>> = None;
    let mut errored_after_buffer = false;
    let mut error_msg = String::new();

    loop {
        if buffered.len() >= sniff_limit {
            break;
        }
        match rec_iter.next() {
            Some(Ok(r)) => {
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                buffered.push(v);
            }
            Some(Err(e)) => {
                errored_after_buffer = true;
                error_msg = format_csv_err(&e);
                break;
            }
            None => break,
        }
    }

    // Determine column count
    let num_cols = if let Some(h) = &header {
        h.len()
    } else if !buffered.is_empty() {
        buffered[0].len()
    } else {
        0
    };

    // Add # column if needed
    let cols_with_num = if app.number { num_cols + 1 } else { num_cols };

    // Compute widths
    let mut widths = vec![0usize; cols_with_num];

    if app.number {
        // # col width: from "#" header (if !no_headers) or 0; will be updated by body row numbers
        if !app.no_headers {
            widths[0] = display_width("#");
        }
    }

    let body_offset = if app.number { 1 } else { 0 };
    if let Some(h) = &header {
        for (i, s) in h.iter().enumerate() {
            let w = display_width(s);
            if w > widths[i + body_offset] {
                widths[i + body_offset] = w;
            }
        }
    }
    for (idx, row) in buffered.iter().enumerate() {
        if app.number {
            let num_str = format!("{}", idx + 1);
            let w = display_width(&num_str);
            if w > widths[0] {
                widths[0] = w;
            }
        }
        for (i, s) in row.iter().enumerate() {
            if i + body_offset >= widths.len() { break; }
            let w = display_width(s);
            if w > widths[i + body_offset] {
                widths[i + body_offset] = w;
            }
        }
    }

    // Streaming pre-fetch: we need to know what row numbers come next if more rows arrive.
    // Width is already locked from buffered, so streaming rows just use locked widths.

    // Now print
    let stdout = io::stdout();
    let mut out = BufWriter::new(stdout.lock());
    let style_def = get_style(app.style);
    let indent_str: String = std::iter::repeat(' ').take(app.indent).collect();
    let pad_str: String = std::iter::repeat(' ').take(app.padding).collect();

    // Top border
    if let Some(top) = &style_def.top {
        write_border(&mut out, &indent_str, top, &widths, app.padding)?;
    }

    // Header row
    let has_header_text = if app.no_headers {
        false
    } else if app.number && cols_with_num > 0 {
        // # column with header "#"
        true
    } else {
        header.is_some()
    };

    if has_header_text {
        let mut row_cells: Vec<String> = Vec::with_capacity(cols_with_num);
        if app.number {
            row_cells.push("#".to_string());
        }
        if let Some(h) = &header {
            for s in h {
                row_cells.push(s.clone());
            }
        } else {
            // -H not set but no header was read? Shouldn't happen if header logic is right
        }
        // Fill if missing
        while row_cells.len() < cols_with_num {
            row_cells.push(String::new());
        }
        write_data_row(&mut out, &indent_str, &pad_str, &style_def, &row_cells, &widths, app.header_align)?;
    }

    // Header separator: only if we have header AND body rows
    let total_body_rows_known = buffered.len() + (if errored_after_buffer { 0 } else { 0 });
    // We need to know if there are body rows AT ALL (buffered or streamable).
    // If sniff_limit was reached we may have more rows. If buffered is empty AND no error AND we haven't tried, try peeking.
    let mut peeked: Option<Result<csv::StringRecord, csv::Error>> = None;
    if has_header_text && total_body_rows_known == 0 && !errored_after_buffer {
        // Try to peek one more record
        match rec_iter.next() {
            Some(r) => peeked = Some(r),
            None => {}
        }
    }
    let has_body = total_body_rows_known > 0 || peeked.as_ref().map_or(false, |r| r.is_ok());

    if has_header_text && has_body {
        if let Some(hsep) = &style_def.header_sep {
            write_border(&mut out, &indent_str, hsep, &widths, app.padding)?;
        }
    }

    // Print buffered body rows
    for (idx, row) in buffered.iter().enumerate() {
        if app.number {
            let mut full_row = vec![format!("{}", idx + 1)];
            full_row.extend(row.iter().cloned());
            write_data_row(&mut out, &indent_str, &pad_str, &style_def, &full_row, &widths, app.body_align)?;
        } else {
            write_data_row(&mut out, &indent_str, &pad_str, &style_def, row, &widths, app.body_align)?;
        }
        // grid: body separator between body rows
        // (only between rows, not after last)
    }

    // Print peeked row if any
    let mut row_count = buffered.len();
    if let Some(r) = peeked {
        match r {
            Ok(rec) => {
                if style_def.body_sep.is_some() && row_count > 0 {
                    write_border(&mut out, &indent_str, style_def.body_sep.as_ref().unwrap(), &widths, app.padding)?;
                }
                let row: Vec<String> = rec.iter().map(|s| s.to_string()).collect();
                row_count += 1;
                if app.number {
                    let mut full_row = vec![format!("{}", row_count)];
                    full_row.extend(row.iter().cloned());
                    write_data_row(&mut out, &indent_str, &pad_str, &style_def, &full_row, &widths, app.body_align)?;
                } else {
                    write_data_row(&mut out, &indent_str, &pad_str, &style_def, &row, &widths, app.body_align)?;
                }
            }
            Err(e) => {
                let _ = out.flush();
                return Err(format_csv_err(&e));
            }
        }
    }

    // Body separators within buffered (between rows for grid)
    // Hmm - I printed all buffered rows without separators. Need to re-do this.
    // Will restructure.

    // Stream remaining
    if !errored_after_buffer {
        loop {
            match rec_iter.next() {
                Some(Ok(rec)) => {
                    if style_def.body_sep.is_some() {
                        write_border(&mut out, &indent_str, style_def.body_sep.as_ref().unwrap(), &widths, app.padding)?;
                    }
                    let row: Vec<String> = rec.iter().map(|s| s.to_string()).collect();
                    row_count += 1;
                    if app.number {
                        let mut full_row = vec![format!("{}", row_count)];
                        full_row.extend(row.iter().cloned());
                        write_data_row(&mut out, &indent_str, &pad_str, &style_def, &full_row, &widths, app.body_align)?;
                    } else {
                        write_data_row(&mut out, &indent_str, &pad_str, &style_def, &row, &widths, app.body_align)?;
                    }
                }
                Some(Err(e)) => {
                    let _ = out.flush();
                    return Err(format_csv_err(&e));
                }
                None => break,
            }
        }
    } else {
        let _ = out.flush();
        return Err(error_msg);
    }

    // Bottom border
    if let Some(bot) = &style_def.bottom {
        write_border(&mut out, &indent_str, bot, &widths, app.padding)?;
    }

    let _ = out.flush();
    Ok(())
}

fn format_csv_err(e: &csv::Error) -> String {
    use csv::ErrorKind;
    match e.kind() {
        ErrorKind::Utf8 { pos, err } => {
            if let Some(pos) = pos {
                format!("CSV parse error: record {} (line {}, field: {}, byte: {}): invalid utf-8: {}",
                    pos.record(), pos.line(), err.field(), pos.byte(), err)
            } else {
                format!("CSV parse error: invalid utf-8: {}", err)
            }
        }
        ErrorKind::UnequalLengths { pos, expected_len, len } => {
            if let Some(pos) = pos {
                format!("CSV error: record {} (line: {}, byte: {}): found record with {} fields, but the previous record has {} fields",
                    pos.record(), pos.line(), pos.byte(), len, expected_len)
            } else {
                format!("CSV error: found record with {} fields, but the previous record has {} fields", len, expected_len)
            }
        }
        _ => format!("{}", e),
    }
}

struct StyleDef {
    top: Option<BorderLine>,
    bottom: Option<BorderLine>,
    header_sep: Option<BorderLine>,
    body_sep: Option<BorderLine>,
    side: String,
    cell_sep: String,
    outer_left: String,
    outer_right: String,
    use_cell_sep: bool,
}

struct BorderLine {
    left: String,
    fill: String,
    tee: String,
    right: String,
}

fn get_style(s: Style) -> StyleDef {
    match s {
        Style::None => StyleDef {
            top: None,
            bottom: None,
            header_sep: None,
            body_sep: None,
            side: String::new(),
            cell_sep: String::new(),
            outer_left: String::new(),
            outer_right: String::new(),
            use_cell_sep: false,
        },
        Style::Ascii => StyleDef {
            top: Some(BorderLine { left: "+".into(), fill: "-".into(), tee: "+".into(), right: "+".into() }),
            bottom: Some(BorderLine { left: "+".into(), fill: "-".into(), tee: "+".into(), right: "+".into() }),
            header_sep: Some(BorderLine { left: "+".into(), fill: "-".into(), tee: "+".into(), right: "+".into() }),
            body_sep: None,
            side: "|".into(),
            cell_sep: "|".into(),
            outer_left: "|".into(),
            outer_right: "|".into(),
            use_cell_sep: true,
        },
        Style::Ascii2 => StyleDef {
            top: None,
            bottom: None,
            header_sep: Some(BorderLine { left: " ".into(), fill: "-".into(), tee: "+".into(), right: " ".into() }),
            body_sep: None,
            side: " ".into(),
            cell_sep: "|".into(),
            outer_left: " ".into(),
            outer_right: " ".into(),
            use_cell_sep: true,
        },
        Style::Sharp => StyleDef {
            top: Some(BorderLine { left: "┌".into(), fill: "─".into(), tee: "┬".into(), right: "┐".into() }),
            bottom: Some(BorderLine { left: "└".into(), fill: "─".into(), tee: "┴".into(), right: "┘".into() }),
            header_sep: Some(BorderLine { left: "├".into(), fill: "─".into(), tee: "┼".into(), right: "┤".into() }),
            body_sep: None,
            side: "│".into(),
            cell_sep: "│".into(),
            outer_left: "│".into(),
            outer_right: "│".into(),
            use_cell_sep: true,
        },
        Style::Rounded => StyleDef {
            top: Some(BorderLine { left: "╭".into(), fill: "─".into(), tee: "┬".into(), right: "╮".into() }),
            bottom: Some(BorderLine { left: "╰".into(), fill: "─".into(), tee: "┴".into(), right: "╯".into() }),
            header_sep: Some(BorderLine { left: "├".into(), fill: "─".into(), tee: "┼".into(), right: "┤".into() }),
            body_sep: None,
            side: "│".into(),
            cell_sep: "│".into(),
            outer_left: "│".into(),
            outer_right: "│".into(),
            use_cell_sep: true,
        },
        Style::Reinforced => StyleDef {
            top: Some(BorderLine { left: "┏".into(), fill: "─".into(), tee: "┬".into(), right: "┓".into() }),
            bottom: Some(BorderLine { left: "┗".into(), fill: "─".into(), tee: "┴".into(), right: "┛".into() }),
            header_sep: Some(BorderLine { left: "├".into(), fill: "─".into(), tee: "┼".into(), right: "┤".into() }),
            body_sep: None,
            side: "│".into(),
            cell_sep: "│".into(),
            outer_left: "│".into(),
            outer_right: "│".into(),
            use_cell_sep: true,
        },
        Style::Markdown => StyleDef {
            top: None,
            bottom: None,
            header_sep: Some(BorderLine { left: "|".into(), fill: "-".into(), tee: "|".into(), right: "|".into() }),
            body_sep: None,
            side: "|".into(),
            cell_sep: "|".into(),
            outer_left: "|".into(),
            outer_right: "|".into(),
            use_cell_sep: true,
        },
        Style::Grid => StyleDef {
            top: Some(BorderLine { left: "┌".into(), fill: "─".into(), tee: "┬".into(), right: "┐".into() }),
            bottom: Some(BorderLine { left: "└".into(), fill: "─".into(), tee: "┴".into(), right: "┘".into() }),
            header_sep: Some(BorderLine { left: "├".into(), fill: "─".into(), tee: "┼".into(), right: "┤".into() }),
            body_sep: Some(BorderLine { left: "├".into(), fill: "─".into(), tee: "┼".into(), right: "┤".into() }),
            side: "│".into(),
            cell_sep: "│".into(),
            outer_left: "│".into(),
            outer_right: "│".into(),
            use_cell_sep: true,
        },
    }
}

fn write_border<W: Write>(out: &mut W, indent: &str, line: &BorderLine,
                          widths: &[usize], padding: usize) -> Result<(), String> {
    let mut buf = String::new();
    buf.push_str(indent);
    buf.push_str(&line.left);
    for (i, w) in widths.iter().enumerate() {
        if i > 0 {
            buf.push_str(&line.tee);
        }
        let span = w + 2 * padding;
        for _ in 0..span {
            buf.push_str(&line.fill);
        }
    }
    buf.push_str(&line.right);
    buf.push('\n');
    out.write_all(buf.as_bytes()).map_err(|e| format!("{}", e))?;
    Ok(())
}

fn write_data_row<W: Write>(out: &mut W, indent: &str, pad: &str, style: &StyleDef,
                            cells: &[String], widths: &[usize], align: Align) -> Result<(), String> {
    let mut buf = String::new();
    buf.push_str(indent);
    buf.push_str(&style.outer_left);
    for (i, _w) in widths.iter().enumerate() {
        if i > 0 && style.use_cell_sep {
            buf.push_str(&style.cell_sep);
        }
        let cell = cells.get(i).map(|s| s.as_str()).unwrap_or("");
        let w = widths[i];
        let (trunc, content_w) = truncate_to_width(cell, w);
        buf.push_str(pad);
        let space_total = w - content_w;
        match align {
            Align::Left => {
                buf.push_str(trunc);
                for _ in 0..space_total { buf.push(' '); }
            }
            Align::Right => {
                for _ in 0..space_total { buf.push(' '); }
                buf.push_str(trunc);
            }
            Align::Center => {
                let l = space_total / 2;
                let r = space_total - l;
                for _ in 0..l { buf.push(' '); }
                buf.push_str(trunc);
                for _ in 0..r { buf.push(' '); }
            }
        }
        buf.push_str(pad);
    }
    buf.push_str(&style.outer_right);
    buf.push('\n');
    out.write_all(buf.as_bytes()).map_err(|e| format!("{}", e))?;
    Ok(())
}

fn truncate_to_width(s: &str, max: usize) -> (&str, usize) {
    let mut acc = 0;
    let mut end_byte = 0;
    for (i, c) in s.char_indices() {
        let w = char_width(c);
        if acc + w > max {
            return (&s[..i], acc);
        }
        acc += w;
        end_byte = i + c.len_utf8();
    }
    (&s[..end_byte], acc)
}

fn display_width(s: &str) -> usize {
    s.chars().map(char_width).sum()
}

fn char_width(c: char) -> usize {
    if c.is_control() {
        return 1;
    }
    use unicode_width::UnicodeWidthChar;
    c.width_cjk().unwrap_or(0)
}

use clap::{Parser, ValueEnum};
use std::io::{self, BufWriter, Read, Write};
use std::process::ExitCode;

#[derive(Copy, Clone, ValueEnum, Debug, PartialEq)]
#[clap(rename_all = "lower")]
enum Style {
    None,
    Ascii,
    Ascii2,
    Sharp,
    Rounded,
    Reinforced,
    Markdown,
    Grid,
}

#[derive(Copy, Clone, ValueEnum, Debug, PartialEq)]
#[clap(rename_all = "lower")]
enum Align {
    Left,
    Center,
    Right,
}

#[derive(Parser, Debug)]
#[clap(
    name = "csview",
    version = "1.3.4",
    about = "A high performance csv viewer with cjk/emoji support."
)]
struct App {
    /// Specify that the input has no header row
    #[clap(short = 'H', long)]
    no_headers: bool,

    /// Prepend a column of line numbers to the table
    #[clap(short = 'n', long)]
    number: bool,

    /// Use '\t' as delimiter for tsv
    #[clap(short = 't', long, conflicts_with = "delimiter")]
    tsv: bool,

    /// Specify the field delimiter
    #[clap(short = 'd', long, default_value_t = ',')]
    delimiter: char,

    /// Specify the border style
    #[clap(short = 's', long, value_enum, default_value_t = Style::Sharp)]
    style: Style,

    /// Specify padding for table cell
    #[clap(short = 'p', long, default_value_t = 1)]
    padding: usize,

    /// Specify global indent for table
    #[clap(short = 'i', long, default_value_t = 0)]
    indent: usize,

    /// Limit column widths sniffing to the specified number of rows. Specify "0" to cancel limit
    #[clap(long, value_name = "LIMIT", default_value_t = 1000)]
    sniff: usize,

    /// Specify the alignment of the table header
    #[clap(long, value_enum, default_value_t = Align::Center)]
    header_align: Align,

    /// Specify the alignment of the table body
    #[clap(long, value_enum, default_value_t = Align::Left)]
    body_align: Align,

    /// Disable pager
    #[clap(short = 'P', long)]
    disable_pager: bool,

    /// File to view
    file: Option<std::path::PathBuf>,
}

fn main() -> ExitCode {
    let app = App::parse();
    match run(app) {
        Ok(()) => ExitCode::SUCCESS,
        Err(e) => {
            eprintln!("csview: {}", e);
            ExitCode::FAILURE
        }
    }
}

fn run(app: App) -> Result<(), String> {
    let delim = if app.tsv {
        b'\t'
    } else {
        let mut buf = [0u8; 4];
        let s = app.delimiter.encode_utf8(&mut buf);
        if s.len() != 1 {
            return Err("delimiter must be a single ASCII byte".to_string());
        }
        buf[0]
    };

    let mut input: Box<dyn Read> = match &app.file {
        Some(p) => match std::fs::File::open(p) {
            Ok(f) => Box::new(f),
            Err(e) => return Err(format_io_err(&e)),
        },
        None => {
            use std::io::IsTerminal;
            if io::stdin().is_terminal() {
                return Err("no input file specified (use -h for help)".to_string());
            }
            Box::new(io::stdin())
        }
    };

    let mut all = Vec::new();
    if let Err(e) = input.read_to_end(&mut all) {
        return Err(format_io_err(&e));
    }

    process(&app, &all, delim)
}

fn format_io_err(e: &std::io::Error) -> String {
    if let Some(c) = e.raw_os_error() {
        let msg = match c {
            2 => "No such file or directory",
            13 => "Permission denied",
            21 => "Is a directory",
            _ => return format!("{}", e),
        };
        format!("{} (os error {})", msg, c)
    } else {
        format!("{}", e)
    }
}

fn format_csv_err(e: &csv::Error) -> String {
    use csv::ErrorKind;
    match e.kind() {
        ErrorKind::Utf8 { pos, err } => {
            if let Some(pos) = pos {
                format!(
                    "CSV parse error: record {} (line {}, field: {}, byte: {}): invalid utf-8: {}",
                    pos.record(),
                    pos.line(),
                    err.field(),
                    pos.byte(),
                    err
                )
            } else {
                format!("CSV parse error: invalid utf-8: {}", err)
            }
        }
        ErrorKind::UnequalLengths {
            pos,
            expected_len,
            len,
        } => {
            if let Some(pos) = pos {
                format!(
                    "CSV error: record {} (line: {}, byte: {}): found record with {} fields, but the previous record has {} fields",
                    pos.record(),
                    pos.line(),
                    pos.byte(),
                    len,
                    expected_len
                )
            } else {
                format!(
                    "CSV error: found record with {} fields, but the previous record has {} fields",
                    len, expected_len
                )
            }
        }
        _ => format!("{}", e),
    }
}

struct BorderLine {
    left: String,
    fill: String,
    tee: String,
    right: String,
}

struct StyleDef {
    top: Option<BorderLine>,
    bottom: Option<BorderLine>,
    header_sep: Option<BorderLine>,
    body_sep: Option<BorderLine>,
    outer_left: String,
    outer_right: String,
    cell_sep: String,
}

