fn process(app: &App, data: &[u8], delim: u8) -> Result<(), String> {
    let mut rdr = csv::ReaderBuilder::new()
        .delimiter(delim)
        .has_headers(false)
        .flexible(false)
        .from_reader(data);

    let mut header: Option<Vec<String>> = None;
    let mut header_read = false;

    let sniff_limit = if app.sniff == 0 {
        usize::MAX
    } else {
        app.sniff
    };

    let mut buffered: Vec<Vec<String>> = Vec::new();
    let mut iter = rdr.records();

    if !app.no_headers {
        match iter.next() {
            Some(Ok(r)) => {
                header_read = true;
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                if !v.is_empty() {
                    header = Some(v);
                }
            }
            Some(Err(e)) => return Err(format_csv_err(&e)),
            None => {}
        }
    }

    let _ = header_read;

    // Read up to sniff body rows
    let mut early_err: Option<String> = None;
    while buffered.len() < sniff_limit {
        match iter.next() {
            Some(Ok(r)) => {
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                buffered.push(v);
            }
            Some(Err(e)) => {
                early_err = Some(format_csv_err(&e));
                break;
            }
            None => break,
        }
    }

    // Determine number of columns
    let num_cols = if let Some(h) = &header {
        h.len()
    } else if !buffered.is_empty() {
        buffered[0].len()
    } else {
        0
    };

    let body_offset = if app.number { 1 } else { 0 };
    let cols_with_num = if app.number { num_cols + 1 } else { num_cols };

    // Compute widths
    let mut widths = vec![0usize; cols_with_num];
    if app.number && !app.no_headers && cols_with_num > 0 {
        widths[0] = display_width("#");
    }
    if let Some(h) = &header {
        for (i, s) in h.iter().enumerate() {
            let idx = i + body_offset;
            if idx < widths.len() {
                let w = display_width(s);
                if w > widths[idx] {
                    widths[idx] = w;
                }
            }
        }
    }
    for (row_idx, row) in buffered.iter().enumerate() {
        if app.number && cols_with_num > 0 {
            let s = format!("{}", row_idx + 1);
            let w = display_width(&s);
            if w > widths[0] {
                widths[0] = w;
            }
        }
        for (i, s) in row.iter().enumerate() {
            let idx = i + body_offset;
            if idx < widths.len() {
                let w = display_width(s);
                if w > widths[idx] {
                    widths[idx] = w;
                }
            }
        }
    }

    // We need to know if there will be any body rows (including streamed) to decide
    // whether to print header separator. Peek the next record if buffered is empty and no error.
    let mut peeked: Option<Vec<String>> = None;
    let mut peek_err: Option<String> = None;
    if buffered.is_empty() && early_err.is_none() {
        match iter.next() {
            Some(Ok(r)) => {
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                peeked = Some(v);
            }
            Some(Err(e)) => {
                peek_err = Some(format_csv_err(&e));
            }
            None => {}
        }
    }

    // If header is None (no header read), num_cols may need to come from peeked
    let mut num_cols = num_cols;
    let mut cols_with_num = cols_with_num;
    let mut widths = widths;
    if num_cols == 0 && peeked.is_some() {
        if let Some(p) = &peeked {
            num_cols = p.len();
            cols_with_num = if app.number { num_cols + 1 } else { num_cols };
            widths = vec![0usize; cols_with_num];
            if app.number && !app.no_headers && cols_with_num > 0 {
                widths[0] = display_width("#");
            }
            for (i, s) in p.iter().enumerate() {
                let idx = i + body_offset;
                if idx < widths.len() {
                    let w = display_width(s);
                    if w > widths[idx] {
                        widths[idx] = w;
                    }
                }
            }
            if app.number && cols_with_num > 0 {
                let s = format!("{}", 1);
                let w = display_width(&s);
                if w > widths[0] {
                    widths[0] = w;
                }
            }
        }
    }

    // Also: when no header AND -H AND no body rows, but -n: # col with min width 1?
    // Observed: -n -H with empty body gave ┌───┐ └───┘ (col width 1). So if number=true
    // and cols_with_num would be 0, min 1 col with width 1.
    if app.number && cols_with_num == 0 {
        cols_with_num = 1;
        widths = vec![1usize];
    }

    let has_body =
        !buffered.is_empty() || peeked.is_some() || (peek_err.is_some());
    // Body rows may come from streaming too; if early_err exists, no streaming will happen.

    // Whether to show the header text row
    let show_header = if app.no_headers {
        // With -H and number: still show "#"? Looking at -n -H test:
        //   printf 'a,b\n' | csview -n -H gave: top, body row "1 a b", bot. So no header row.
        false
    } else {
        header.is_some() || app.number
    };

    // For empty input with -H and no -n: don't show header (and no body), just minimal box.
    // For empty input without -H: header is None, show_header would only be true if -n.

    let style_def = get_style(app.style);
    let indent_str: String = std::iter::repeat(' ').take(app.indent).collect();
    let pad_str: String = std::iter::repeat(' ').take(app.padding).collect();

    let stdout = io::stdout();
    let mut out = BufWriter::new(stdout.lock());

    // Top border
    if let Some(top) = &style_def.top {
        write_border(&mut out, &indent_str, top, &widths, app.padding)?;
    }

    // Header row
    if show_header {
        let mut row_cells: Vec<String> = Vec::with_capacity(cols_with_num);
        if app.number {
            row_cells.push("#".to_string());
        }
        if let Some(h) = &header {
            for s in h {
                row_cells.push(s.clone());
            }
        }
        while row_cells.len() < cols_with_num {
            row_cells.push(String::new());
        }
        write_data_row(
            &mut out,
            &indent_str,
            &pad_str,
            &style_def,
            &row_cells,
            &widths,
            app.header_align,
        )?;
    }

    // Header separator if header is shown and body exists
    if show_header && has_body {
        if let Some(hs) = &style_def.header_sep {
            write_border(&mut out, &indent_str, hs, &widths, app.padding)?;
        }
    }

    // Print buffered + peeked + streamed body rows
    let mut row_idx: usize = 0;
    let mut first_body = true;
    let mut all_body_iter: Vec<Vec<String>> = Vec::new();
    for r in buffered.into_iter() {
        all_body_iter.push(r);
    }
    if let Some(p) = peeked {
        all_body_iter.push(p);
    }

    for row in all_body_iter.iter() {
        if !first_body {
            if let Some(bs) = &style_def.body_sep {
                write_border(&mut out, &indent_str, bs, &widths, app.padding)?;
            }
        }
        first_body = false;
        row_idx += 1;
        let cells = if app.number {
            let mut v = vec![format!("{}", row_idx)];
            v.extend(row.iter().cloned());
            v
        } else {
            row.clone()
        };
        write_data_row(
            &mut out,
            &indent_str,
            &pad_str,
            &style_def,
            &cells,
            &widths,
            app.body_align,
        )?;
    }

    // If buffered was empty and we peeked with an error, propagate
    if let Some(e) = peek_err {
        let _ = out.flush();
        return Err(e);
    }

    // Stream remaining
    if early_err.is_none() {
        loop {
            match iter.next() {
                Some(Ok(r)) => {
                    let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                    if !first_body {
                        if let Some(bs) = &style_def.body_sep {
                            write_border(&mut out, &indent_str, bs, &widths, app.padding)?;
                        }
                    }
                    first_body = false;
                    row_idx += 1;
                    let cells = if app.number {
                        let mut x = vec![format!("{}", row_idx)];
                        x.extend(v.iter().cloned());
                        x
                    } else {
                        v
                    };
                    write_data_row(
                        &mut out,
                        &indent_str,
                        &pad_str,
                        &style_def,
                        &cells,
                        &widths,
                        app.body_align,
                    )?;
                }
                Some(Err(e)) => {
                    let _ = out.flush();
                    return Err(format_csv_err(&e));
                }
                None => break,
            }
        }
    } else {
        let _ = out.flush();
        return Err(early_err.unwrap());
    }

    // Bottom border
    if let Some(bot) = &style_def.bottom {
        write_border(&mut out, &indent_str, bot, &widths, app.padding)?;
    }

    let _ = out.flush();
    Ok(())
}

fn write_border<W: Write>(
    out: &mut W,
    indent: &str,
    line: &BorderLine,
    widths: &[usize],
    padding: usize,
) -> Result<(), String> {
    let mut buf = String::new();
    buf.push_str(indent);
    buf.push_str(&line.left);
    for (i, w) in widths.iter().enumerate() {
        if i > 0 {
            buf.push_str(&line.tee);
        }
        let span = w + 2 * padding;
        for _ in 0..span {
            buf.push_str(&line.fill);
        }
    }
    buf.push_str(&line.right);
    buf.push('\n');
    out.write_all(buf.as_bytes())
        .map_err(|e| format!("{}", e))?;
    Ok(())
}

fn write_data_row<W: Write>(
    out: &mut W,
    indent: &str,
    pad: &str,
    style: &StyleDef,
    cells: &[String],
    widths: &[usize],
    align: Align,
) -> Result<(), String> {
    let mut buf = String::new();
    buf.push_str(indent);
    buf.push_str(&style.outer_left);
    for i in 0..widths.len() {
        if i > 0 {
            buf.push_str(&style.cell_sep);
        }
        let cell = cells.get(i).map(|s| s.as_str()).unwrap_or("");
        let w = widths[i];
        let (trunc, content_w) = truncate_to_width(cell, w);
        buf.push_str(pad);
        let space_total = w - content_w;
        match align {
            Align::Left => {
                buf.push_str(trunc);
                for _ in 0..space_total {
                    buf.push(' ');
                }
            }
            Align::Right => {
                for _ in 0..space_total {
                    buf.push(' ');
                }
                buf.push_str(trunc);
            }
            Align::Center => {
                let l = space_total / 2;
                let r = space_total - l;
                for _ in 0..l {
                    buf.push(' ');
                }
                buf.push_str(trunc);
                for _ in 0..r {
                    buf.push(' ');
                }
            }
        }
        buf.push_str(pad);
    }
    buf.push_str(&style.outer_right);
    buf.push('\n');
    out.write_all(buf.as_bytes())
        .map_err(|e| format!("{}", e))?;
    Ok(())
}

fn truncate_to_width(s: &str, max: usize) -> (&str, usize) {
    let mut acc = 0;
    let mut end_byte = 0;
    for (i, c) in s.char_indices() {
        let w = char_width(c);
        if acc + w > max {
            return (&s[..i], acc);
        }
        acc += w;
        end_byte = i + c.len_utf8();
    }
    (&s[..end_byte], acc)
}

fn display_width(s: &str) -> usize {
    s.chars().map(char_width).sum()
}

fn char_width(c: char) -> usize {
    if c.is_control() {
        return 1;
    }
    use unicode_width::UnicodeWidthChar;
    c.width_cjk().unwrap_or(0)
}

use clap::{Parser, ValueEnum};
use std::io::{self, BufWriter, Read, Write};
use std::process::ExitCode;

#[derive(Copy, Clone, ValueEnum, Debug, PartialEq)]
#[clap(rename_all = "lower")]
enum Style {
    None,
    Ascii,
    Ascii2,
    Sharp,
    Rounded,
    Reinforced,
    Markdown,
    Grid,
}

#[derive(Copy, Clone, ValueEnum, Debug, PartialEq)]
#[clap(rename_all = "lower")]
enum Align {
    Left,
    Center,
    Right,
}

#[derive(Parser, Debug)]
#[clap(
    name = "csview",
    version = "1.3.4",
    about = "A high performance csv viewer with cjk/emoji support."
)]
struct App {
    /// Specify that the input has no header row
    #[clap(short = 'H', long)]
    no_headers: bool,

    /// Prepend a column of line numbers to the table
    #[clap(short = 'n', long)]
    number: bool,

    /// Use '\t' as delimiter for tsv
    #[clap(short = 't', long, conflicts_with = "delimiter")]
    tsv: bool,

    /// Specify the field delimiter
    #[clap(short = 'd', long, default_value_t = ',')]
    delimiter: char,

    /// Specify the border style
    #[clap(short = 's', long, value_enum, default_value_t = Style::Sharp)]
    style: Style,

    /// Specify padding for table cell
    #[clap(short = 'p', long, default_value_t = 1)]
    padding: usize,

    /// Specify global indent for table
    #[clap(short = 'i', long, default_value_t = 0)]
    indent: usize,

    /// Limit column widths sniffing to the specified number of rows. Specify "0" to cancel limit
    #[clap(long, value_name = "LIMIT", default_value_t = 1000)]
    sniff: usize,

    /// Specify the alignment of the table header
    #[clap(long, value_enum, default_value_t = Align::Center)]
    header_align: Align,

    /// Specify the alignment of the table body
    #[clap(long, value_enum, default_value_t = Align::Left)]
    body_align: Align,

    /// Disable pager
    #[clap(short = 'P', long)]
    disable_pager: bool,

    /// File to view
    file: Option<std::path::PathBuf>,
}

fn main() -> ExitCode {
    let app = App::parse();
    match run(app) {
        Ok(()) => ExitCode::SUCCESS,
        Err(e) => {
            eprintln!("csview: {}", e);
            ExitCode::FAILURE
        }
    }
}

fn run(app: App) -> Result<(), String> {
    let delim = if app.tsv {
        b'\t'
    } else {
        let mut buf = [0u8; 4];
        let s = app.delimiter.encode_utf8(&mut buf);
        if s.len() != 1 {
            return Err("delimiter must be a single ASCII byte".to_string());
        }
        buf[0]
    };

    let mut input: Box<dyn Read> = match &app.file {
        Some(p) => match std::fs::File::open(p) {
            Ok(f) => Box::new(f),
            Err(e) => return Err(format_io_err(&e)),
        },
        None => {
            use std::io::IsTerminal;
            if io::stdin().is_terminal() {
                return Err("no input file specified (use -h for help)".to_string());
            }
            Box::new(io::stdin())
        }
    };

    let mut all = Vec::new();
    if let Err(e) = input.read_to_end(&mut all) {
        return Err(format_io_err(&e));
    }

    process(&app, &all, delim)
}

fn format_io_err(e: &std::io::Error) -> String {
    if let Some(c) = e.raw_os_error() {
        let msg = match c {
            2 => "No such file or directory",
            13 => "Permission denied",
            21 => "Is a directory",
            _ => return format!("{}", e),
        };
        format!("{} (os error {})", msg, c)
    } else {
        format!("{}", e)
    }
}

fn format_csv_err(e: &csv::Error) -> String {
    use csv::ErrorKind;
    match e.kind() {
        ErrorKind::Utf8 { pos, err } => {
            if let Some(pos) = pos {
                format!(
                    "CSV parse error: record {} (line {}, field: {}, byte: {}): invalid utf-8: {}",
                    pos.record(),
                    pos.line(),
                    err.field(),
                    pos.byte(),
                    err
                )
            } else {
                format!("CSV parse error: invalid utf-8: {}", err)
            }
        }
        ErrorKind::UnequalLengths {
            pos,
            expected_len,
            len,
        } => {
            if let Some(pos) = pos {
                format!(
                    "CSV error: record {} (line: {}, byte: {}): found record with {} fields, but the previous record has {} fields",
                    pos.record(),
                    pos.line(),
                    pos.byte(),
                    len,
                    expected_len
                )
            } else {
                format!(
                    "CSV error: found record with {} fields, but the previous record has {} fields",
                    len, expected_len
                )
            }
        }
        _ => format!("{}", e),
    }
}

struct BorderLine {
    left: String,
    fill: String,
    tee: String,
    right: String,
}

struct StyleDef {
    top: Option<BorderLine>,
    bottom: Option<BorderLine>,
    header_sep: Option<BorderLine>,
    body_sep: Option<BorderLine>,
    outer_left: String,
    outer_right: String,
    cell_sep: String,
}

