fn process(app: &App, data: &[u8], delim: u8) -> Result<(), String> {
    let mut rdr = csv::ReaderBuilder::new()
        .delimiter(delim)
        .has_headers(false)
        .flexible(false)
        .from_reader(data);

    let mut header: Option<Vec<String>> = None;
    let mut header_read = false;

    let sniff_limit = if app.sniff == 0 {
        usize::MAX
    } else {
        app.sniff
    };

    let mut buffered: Vec<Vec<String>> = Vec::new();
    let mut iter = rdr.records();

    if !app.no_headers {
        match iter.next() {
            Some(Ok(r)) => {
                header_read = true;
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                if !v.is_empty() {
                    header = Some(v);
                }
            }
            Some(Err(e)) => return Err(format_csv_err(&e)),
            None => {}
        }
    }

    let _ = header_read;

    // Read up to sniff body rows
    let mut early_err: Option<String> = None;
    while buffered.len() < sniff_limit {
        match iter.next() {
            Some(Ok(r)) => {
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                buffered.push(v);
            }
            Some(Err(e)) => {
                early_err = Some(format_csv_err(&e));
                break;
            }
            None => break,
        }
    }

    // Determine number of columns
    let num_cols = if let Some(h) = &header {
        h.len()
    } else if !buffered.is_empty() {
        buffered[0].len()
    } else {
        0
    };

    let body_offset = if app.number { 1 } else { 0 };
    let cols_with_num = if app.number { num_cols + 1 } else { num_cols };

    // Compute widths
    let mut widths = vec![0usize; cols_with_num];
    if app.number && !app.no_headers && cols_with_num > 0 {
        widths[0] = display_width("#");
    }
    if let Some(h) = &header {
        for (i, s) in h.iter().enumerate() {
            let idx = i + body_offset;
            if idx < widths.len() {
                let w = display_width(s);
                if w > widths[idx] {
                    widths[idx] = w;
                }
            }
        }
    }
    for (row_idx, row) in buffered.iter().enumerate() {
        if app.number && cols_with_num > 0 {
            let s = format!("{}", row_idx + 1);
            let w = display_width(&s);
            if w > widths[0] {
                widths[0] = w;
            }
        }
        for (i, s) in row.iter().enumerate() {
            let idx = i + body_offset;
            if idx < widths.len() {
                let w = display_width(s);
                if w > widths[idx] {
                    widths[idx] = w;
                }
            }
        }
    }

    // We need to know if there will be any body rows (including streamed) to decide
    // whether to print header separator. Peek the next record if buffered is empty and no error.
    let mut peeked: Option<Vec<String>> = None;
    let mut peek_err: Option<String> = None;
    if buffered.is_empty() && early_err.is_none() {
        match iter.next() {
            Some(Ok(r)) => {
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                peeked = Some(v);
            }
            Some(Err(e)) => {
                peek_err = Some(format_csv_err(&e));
            }
            None => {}
        }
    }

    // If header is None (no header read), num_cols may need to come from peeked
    let mut num_cols = num_cols;
    let mut cols_with_num = cols_with_num;
    let mut widths = widths;
    if num_cols == 0 && peeked.is_some() {
        if let Some(p) = &peeked {
            num_cols = p.len();
            cols_with_num = if app.number { num_cols + 1 } else { num_cols };
            widths = vec![0usize; cols_with_num];
            if app.number && !app.no_headers && cols_with_num > 0 {
                widths[0] = display_width("#");
            }
            for (i, s) in p.iter().enumerate() {
                let idx = i + body_offset;
                if idx < widths.len() {
                    let w = display_width(s);
                    if w > widths[idx] {
                        widths[idx] = w;
                    }
                }
            }
            if app.number && cols_with_num > 0 {
                let s = format!("{}", 1);
                let w = display_width(&s);
                if w > widths[0] {
                    widths[0] = w;
                }
            }
        }
    }

    // Also: when no header AND -H AND no body rows, but -n: # col with min width 1?
    // Observed: -n -H with empty body gave ┌───┐ └───┘ (col width 1). So if number=true
    // and cols_with_num would be 0, min 1 col with width 1.
    if app.number && cols_with_num == 0 {
        cols_with_num = 1;
        widths = vec![1usize];
    }

    let has_body =
        !buffered.is_empty() || peeked.is_some() || (peek_err.is_some());
    // Body rows may come from streaming too; if early_err exists, no streaming will happen.

    // Whether to show the header text row
    let show_header = if app.no_headers {
        // With -H and number: still show "#"? Looking at -n -H test:
        //   printf 'a,b\n' | csview -n -H gave: top, body row "1 a b", bot. So no header row.
        false
    } else {
        header.is_some() || app.number
    };

    // For empty input with -H and no -n: don't show header (and no body), just minimal box.
    // For empty input without -H: header is None, show_header would only be true if -n.

    let style_def = get_style(app.style);
    let indent_str: String = std::iter::repeat(' ').take(app.indent).collect();
    let pad_str: String = std::iter::repeat(' ').take(app.padding).collect();

    let stdout = io::stdout();
    let mut out = BufWriter::new(stdout.lock());

    // Top border
    if let Some(top) = &style_def.top {
        write_border(&mut out, &indent_str, top, &widths, app.padding)?;
    }

    // Header row
    if show_header {
        let mut row_cells: Vec<String> = Vec::with_capacity(cols_with_num);
        if app.number {
            row_cells.push("#".to_string());
        }
        if let Some(h) = &header {
            for s in h {
                row_cells.push(s.clone());
            }
        }
        while row_cells.len() < cols_with_num {
            row_cells.push(String::new());
        }
        write_data_row(
            &mut out,
            &indent_str,
            &pad_str,
            &style_def,
            &row_cells,
            &widths,
            app.header_align,
        )?;
    }

    // Header separator if header is shown and body exists
    if show_header && has_body {
        if let Some(hs) = &style_def.header_sep {
            write_border(&mut out, &indent_str, hs, &widths, app.padding)?;
        }
    }

    // Print buffered + peeked + streamed body rows
    let mut row_idx: usize = 0;
    let mut first_body = true;
    let mut all_body_iter: Vec<Vec<String>> = Vec::new();
    for r in buffered.into_iter() {
        all_body_iter.push(r);
    }
    if let Some(p) = peeked {
        all_body_iter.push(p);
    }

    for row in all_body_iter.iter() {
        if !first_body {
            if let Some(bs) = &style_def.body_sep {
                write_border(&mut out, &indent_str, bs, &widths, app.padding)?;
            }
        }
        first_body = false;
        row_idx += 1;
        let cells = if app.number {
            let mut v = vec![format!("{}", row_idx)];
            v.extend(row.iter().cloned());
            v
        } else {
            row.clone()
        };
        write_data_row(
            &mut out,
            &indent_str,
            &pad_str,
            &style_def,
            &cells,
            &widths,
            app.body_align,
        )?;
    }

    // If buffered was empty and we peeked with an error, propagate
    if let Some(e) = peek_err {
        let _ = out.flush();
        return Err(e);
    }

    // Stream remaining
    if early_err.is_none() {
        loop {
            match iter.next() {
                Some(Ok(r)) => {
                    let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                    if !first_body {
                        if let Some(bs) = &style_def.body_sep {
                            write_border(&mut out, &indent_str, bs, &widths, app.padding)?;
                        }
                    }
                    first_body = false;
                    row_idx += 1;
                    let cells = if app.number {
                        let mut x = vec![format!("{}", row_idx)];
                        x.extend(v.iter().cloned());
                        x
                    } else {
                        v
                    };
                    write_data_row(
                        &mut out,
                        &indent_str,
                        &pad_str,
                        &style_def,
                        &cells,
                        &widths,
                        app.body_align,
                    )?;
                }
                Some(Err(e)) => {
                    let _ = out.flush();
                    return Err(format_csv_err(&e));
                }
                None => break,
            }
        }
    } else {
        let _ = out.flush();
        return Err(early_err.unwrap());
    }

