            Some(Ok(r)) => {
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                buffered.push(v);
            }
            Some(Err(e)) => {
                return Err(format_csv_err(&e));
            }
            None => break,
        }
    }

    let body_offset = if app.number { 1 } else { 0 };

    let header_cols = header.as_ref().map(|h| h.len()).unwrap_or(0);
    let body_cols = buffered.first().map(|r| r.len()).unwrap_or(0);
    let mut num_cols = header_cols.max(body_cols);

    // Compute widths
    let mut cols_with_num = if app.number { num_cols + 1 } else { num_cols };

    let mut widths = vec![0usize; cols_with_num];
