        };
        write_data_row(
            &mut out,
            &indent_str,
            &pad_str,
            &style_def,
            &cells,
            &widths,
            app.body_align,
        )?;
    }

    // Stream remaining (if sniff limit was reached)
    loop {
        match iter.next() {
            Some(Ok(r)) => {
                let v: Vec<String> = r.iter().map(|s| s.to_string()).collect();
                if !first_body {
                    if let Some(bs) = &style_def.body_sep {
                        write_border(&mut out, &indent_str, bs, &widths, app.padding)?;
                    }
                }
                first_body = false;
