fn truncate_to_width(s: &str, max: usize) -> (&str, usize) {
    // Fast path: if full width already fits, return as-is.
    let total = display_width(s);
    if total <= max {
        return (s, total);
    }
    // Otherwise scan char-by-char keeping the longest prefix whose
    // display width does not exceed max.
    let mut last_good_end = 0;
    let mut last_good_w = 0;
    for (i, c) in s.char_indices() {
        let new_end = i + c.len_utf8();
        let prefix = &s[..new_end];
        let w = display_width(prefix);
        if w > max {
            return (&s[..last_good_end], last_good_w);
        }
        last_good_end = new_end;
        last_good_w = w;
    }
    (&s[..last_good_end], last_good_w)
}

