fn truncate_to_width(s: &str, max: usize) -> (&str, usize) {
    // Fast path: if full width already fits, return as-is with render width.
    let size_w = sizing_width(s);
    if size_w <= max {
        return (s, render_width(s));
    }
    // Otherwise scan char-by-char keeping the longest prefix whose
    // sizing width does not exceed max.
    let mut last_good_end = 0;
    let mut last_good_w = 0;
