        let new_end = i + c.len_utf8();
        let prefix = &s[..new_end];
        let w = sizing_width(prefix);
        if w > max {
            return (&s[..last_good_end], render_width(&s[..last_good_end]));
        }
        last_good_end = new_end;
        last_good_w = w;
    }
    let _ = last_good_w;
    (&s[..last_good_end], render_width(&s[..last_good_end]))
}

