input.new_string:
fn truncate_to_width(s: &str, max: usize) -> (&str, usize) {
    use unicode_segmentation::UnicodeSegmentation;
    // Fast path: if full render width already fits, return as-is.
    let r_w = render_width(s);
    if r_w <= max {
        return (s, r_w);
    }
    // Otherwise scan grapheme-by-grapheme keeping the longest prefix whose
    // render width does not exceed max. We must split at grapheme boundaries
    // so that emoji presentation sequences (base + VS16) and other multi-char
    // graphemes are kept intact or dropped entirely.
    let mut total_w = 0;
    let mut end_byte = 0;
    for (start, g) in s.grapheme_indices(true) {
        let gw = render_width(g);
        if total_w + gw > max {
            break;
        }
        total_w += gw;
        end_byte = start + g.len();
    }
    (&s[..end_byte], total_w)
}

