import subprocess
import random
import sys

REF = "/workspace/executable"
IMPL = "/work/work/executable"

random.seed(99)

def run(binary, args, input_data):
    p = subprocess.run([binary] + args, input=input_data, capture_output=True, timeout=30)
    return (p.returncode, p.stdout, p.stderr)

ascii_chars = list("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 !@#$%^&*()_+-={}[]:;<>?")
common_cjk = list("你好世界中国日本本来星期")
common_emoji = ["😀", "👍", "❤️", "🌍", "🎉", "☃", "★", "♥", "□", "△"]

passed = 0
failed = 0
failures = []

for i in range(2500):
    cols = random.randint(1, 10)
    rows = random.randint(0, 15)

    rows_data = []
    for _ in range(rows + 1):
        row = []
        for _ in range(cols):
            choice = random.random()
            if choice < 0.5:
                cell = ''.join(random.choice(ascii_chars) for _ in range(random.randint(0, 10)))
            elif choice < 0.8:
                cell = ''.join(random.choice(ascii_chars + common_cjk) for _ in range(random.randint(0, 6)))
            else:
                cell = ''.join(random.choice(ascii_chars + common_emoji) for _ in range(random.randint(0, 5)))
            row.append(cell)
        rows_data.append(row)

    delim_choice = random.choice([",", ";", "|"])
    def escape(f, delim):
        if delim in f or '"' in f or '\n' in f or '\r' in f:
            return '"' + f.replace('"', '""') + '"'
        return f

    input_lines = [delim_choice.join(escape(f, delim_choice) for f in row) for row in rows_data]
    input_data = ('\n'.join(input_lines) + '\n').encode('utf-8', errors='replace')

    styles = ["none", "ascii", "ascii2", "sharp", "rounded", "reinforced", "markdown", "grid"]
    args = ["-s", random.choice(styles), "-p", str(random.choice([0, 1, 2, 3, 5]))]
    if delim_choice != ",":
        args.extend(["-d", delim_choice])
    if random.random() < 0.4:
        args.extend(["-i", str(random.choice([0, 1, 2, 4, 8]))])
    if random.random() < 0.3:
        args.append("-H")
    if random.random() < 0.3:
        args.append("-n")
    if random.random() < 0.4:
        args.extend(["--sniff", str(random.choice([0, 1, 2, 3, 5, 10, 50]))])
    if random.random() < 0.3:
        args.extend(["--header-align", random.choice(["left", "center", "right"])])
    if random.random() < 0.3:
        args.extend(["--body-align", random.choice(["left", "center", "right"])])

    ref = run(REF, args, input_data)
    impl = run(IMPL, args, input_data)
    if ref == impl:
        passed += 1
    else:
        failed += 1
        if len(failures) < 3:
            failures.append((args, input_data, ref, impl))

print(f"PASS: {passed}, FAIL: {failed}")
for args, input_data, ref, impl in failures:
    print(f"\nargs: {args}")
    print(f"input: {input_data[:200]!r}")
    if ref[0] != impl[0]:
        print(f"Exit diff: ref={ref[0]}, imp={impl[0]}")
    if ref[1] != impl[1]:
        for j, (r, m) in enumerate(zip(ref[1].split(b'\n'), impl[1].split(b'\n'))):
            if r != m:
                print(f"Line {j}:\n  REF: {r!r}\n  IMP: {m!r}")
                break
    if ref[2] != impl[2]:
        print(f"Stderr diff:\n  REF: {ref[2]!r}\n  IMP: {impl[2]!r}")
