use std::io::Cursor;
fn main() {
    let input = "a,b\n\xff\xfe,3\n";
    let data = b"a,b\n\xff\xfe,3\n";
    let mut rdr = csv::ReaderBuilder::new()
        .delimiter(b',')
        .has_headers(false)
        .from_reader(Cursor::new(data.as_slice()));
    for r in rdr.records() {
        match r {
            Ok(_) => {}
            Err(e) => {
                println!("Default: {}", e);
                println!("Debug: {:?}", e);
                println!("Kind: {:?}", e.kind());
                match e.kind() {
                    csv::ErrorKind::Utf8 { pos, err } => {
                        println!("Utf8 err: {}", err);
                        println!("Utf8 err Debug: {:?}", err);
                    }
                    csv::ErrorKind::UnequalLengths { pos, expected_len, len } => {
                        println!("UnequalLengths: expected={} len={} pos={:?}", expected_len, len, pos);
                    }
                    _ => {}
                }
            }
        }
    }

    // Test unequal lengths
    println!("\n=== Unequal lengths ===");
    let data2 = b"a,b\n1,2,3\n";
    let mut rdr2 = csv::ReaderBuilder::new()
        .delimiter(b',')
        .has_headers(false)
        .from_reader(Cursor::new(data2.as_slice()));
    for r in rdr2.records() {
        match r {
            Ok(_) => {}
            Err(e) => {
                println!("Default: {}", e);
                match e.kind() {
                    csv::ErrorKind::UnequalLengths { pos, expected_len, len } => {
                        println!("Direct: {}", e);
                        println!("Computed: record {} (line: {}, byte: {}): found record with {} fields, but the previous record has {} fields",
                            pos.as_ref().unwrap().record(), pos.as_ref().unwrap().line(), pos.as_ref().unwrap().byte(),
                            len, expected_len);
                    }
                    _ => {}
                }
            }
        }
    }
}
